// /modules/billing/routes/forecast.ts
import { defineRoute } from 'aether';
import { requireUser, getSession } from '/lib/auth';
import { Result, ok, err } from '/lib/result';
import { parseQuery } from '/lib/validate';
import { getBillingForecast } from '/modules/billing/lib/queries';

export default defineRoute({
  method: 'GET',
  path: '/billing/forecast',
  auth: true,
  async handler(req) {
    const user = await requireUser(req);
    if (!user) return err('Unauthorized');

    const session = await getSession(req);
    if (!session) return err('Session expired');

    const querySchema = z.object({
      period: z.string().default('3-months'),
    });

    const { period } = parseQuery(querySchema, req.query);

    try {
      const forecast = await getBillingForecast(user.id, period);
      return ok(forecast);
    } catch (error) {
      return err(error.message);
    }
  },
});

